def select_next_node(current_node, destination_node, unvisited_nodes, distance_matrix):
    max_sum_distance = -1
    next_node = None

    for node in unvisited_nodes:
        if node == destination_node:
            continue

        distances_to_other_nodes = [distance_matrix[node][other_node] for other_node in unvisited_nodes if other_node != node]
        sum_distance = np.sum(distances_to_other_nodes)

        if sum_distance > max_sum_distance:
            max_sum_distance = sum_distance
            next_node = node

    return next_node

